#!/usr/bin/env node
// Custom analysis script for SevenDRL.js — maps every minified class
// identifier to its real Haxe package name, identifies class boundaries,
// and produces the data needed for modularization.

const fs = require("fs");
const path = require("path");

const bundlePath = path.join(__dirname, "SevenDRL.js");
const src = fs.readFileSync(bundlePath, "utf8");
const lines = src.split("\n");

console.log(`Bundle: ${bundlePath}`);
console.log(`Total lines: ${lines.length}`);
console.log(`Total size: ${(src.length / 1024).toFixed(1)} KB\n`);

// ── Pass 1: Find all class registrations ──────────────────────────────
// Pattern: $hxClasses["com.watabou.foo.Bar"] = minifiedName;
// or:      g["com.watabou.foo.Bar"] = minifiedName;
const classRegs = [];
const regRe = /\$hxClasses\["([\w.]+)"\]\s*=\s*([A-Za-z_$][\w$]*);/g;
let m;
while ((m = regRe.exec(src))) {
  classRegs.push({
    realName: m[1],
    minified: m[2],
    offset: m.index,
    line: src.slice(0, m.index).split("\n").length,
  });
}

// Also catch g["..."] registrations (used by watabou utils/geom)
const gRegRe = /g\["([\w.]+)"\]\s*=\s*([A-Za-z_$][\w$]*);/g;
while ((m = gRegRe.exec(src))) {
  // Avoid duplicates with $hxClasses
  if (!classRegs.find(c => c.realName === m[1])) {
    classRegs.push({
      realName: m[1],
      minified: m[2],
      offset: m.index,
      line: src.slice(0, m.index).split("\n").length,
    });
  }
}

// Also catch enum registrations: $hxEnums["..."] = { ... }
const enumRe = /\$hxEnums\["([\w.]+)"\]\s*=\s*\{/g;
while ((m = enumRe.exec(src))) {
  if (!classRegs.find(c => c.realName === m[1])) {
    classRegs.push({
      realName: m[1],
      minified: null, // enums don't have a single minified var
      offset: m.index,
      line: src.slice(0, m.index).split("\n").length,
      kind: "enum",
    });
  }
}

classRegs.sort((a, b) => a.offset - b.offset);

// ── Pass 2: Find all var declarations (class constructors) ────────────
// Pattern: var com_watabou_sevendrl_SevenDRL = function() {
const varDeclRe = /^(var\s+([A-Za-z_$][\w$]*)\s*=\s*function)/gm;
const varDecls = [];
const varDeclLines = new Map(); // line -> { name, isClass }
for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  const vm = line.match(/^var\s+([A-Za-z_$][\w$]*)\s*=\s*(function|\$hxEnums)/);
  if (vm) {
    varDecls.push({ name: vm[1], line: i + 1, offset: lines.slice(0, i).join("\n").length });
    varDeclLines.set(i + 1, { name: vm[1], isClass: true });
  }
}

// ── Pass 3: Find __name__ assignments for reverse mapping ──────────────
const nameAssignRe = /^([A-Za-z_$][\w$]*)\.__name__\s*=\s*"([^"]+)"/gm;
const nameMap = new Map(); // minified -> realName
while ((m = nameAssignRe.exec(src))) {
  nameMap.set(m[1], m[2]);
}

// ── Pass 4: Find __super__ (inheritance) ──────────────────────────────
const superRe = /^([A-Za-z_$][\w$]*)\.__super__\s*=\s*([A-Za-z_$][\w$]*);/gm;
const inheritance = []; // { child, parent, line }
while ((m = superRe.exec(src))) {
  const line = src.slice(0, m.index).split("\n").length;
  inheritance.push({ child: m[1], parent: m[2], line });
}

// ── Pass 5: Find .prototype = { ... } boundaries ──────────────────────
const protoRe = /^([A-Za-z_$][\w$]*)\.prototype\s*=\s*\{/gm;
const prototypes = []; // { name, line }
while ((m = protoRe.exec(src))) {
  prototypes.push({ name: m[1], line: src.slice(0, m.index).split("\n").length });
}

// ── Classify packages ─────────────────────────────────────────────────
const packages = new Map();
for (const reg of classRegs) {
  const parts = reg.realName.split(".");
  const pkg = parts.length > 1 ? parts.slice(0, -1).join(".") : "(top-level)";
  if (!packages.has(pkg)) packages.set(pkg, []);
  packages.get(pkg).push(reg);
}

// Classify as game-specific vs runtime vs tracery
function classifyPackage(pkg) {
  if (pkg.startsWith("com.watabou.sevendrl")) return "game";
  if (pkg.startsWith("com.watabou.tracery")) return "tracery";
  if (pkg.startsWith("com.watabou.utils")) return "watabou-utils";
  if (pkg.startsWith("com.watabou.geom")) return "watabou-geom";
  if (pkg.startsWith("com.watabou.processes")) return "watabou-processes";
  if (pkg.startsWith("com.watabou.coogee")) return "watabou-engine";
  if (pkg.startsWith("lime.") || pkg.startsWith("openfl.") || pkg.startsWith("haxe.")) return "runtime";
  if (pkg.startsWith("js_Boot") || pkg.startsWith("msignal_")) return "runtime";
  return "other";
}

// ── Output: Full glossary ─────────────────────────────────────────────
let md = `# SevenDRL.js Identifier Glossary\n\n`;
md += `Auto-generated by \`analyze-bundle.js\` — maps every compiled class\n`;
md += `to its real Haxe package name, grouped by subsystem.\n\n`;
md += `**Totals:** ${classRegs.length} classes/enums found, ${nameMap.size} resolved via \`__name__\`\n\n`;

// Summary by classification
const byClass = {};
for (const [pkg] of packages) {
  const cat = classifyPackage(pkg);
  if (!byClass[cat]) byClass[cat] = [];
  byClass[cat].push(pkg);
}
md += `## Package Categories\n\n`;
md += `| Category | Packages | Purpose |\n`;
md += `|---|---|---|\n`;
md += `| **game** | ${byClass.game?.length || 0} | Core Dark Clues game logic |\n`;
md += `| **tracery** | ${byClass.tracery?.length || 0} | Procedural text generation |\n`;
md += `| **watabou-utils** | ${byClass["watabou-utils"]?.length || 0} | Shared utility classes |\n`;
md += `| **watabou-geom** | ${byClass["watabou-geom"]?.length || 0} | Geometry/math helpers |\n`;
md += `| **watabou-processes** | ${byClass["watabou-processes"]?.length || 0} | Process/tween system |\n`;
md += `| **watabou-engine** | ${byClass["watabou-engine"]?.length || 0} | Coogee engine (Game/Scene) |\n`;
md += `| **runtime** | ${byClass.runtime?.length || 0} | Lime/OpenFL/Haxe/JS runtime |\n`;
md += `| **other** | ${byClass.other?.length || 0} | Unclassified |\n\n`;

// Detailed per-category listings
for (const [cat, pkgs] of Object.entries(byClass).sort((a, b) => a[0].localeCompare(b[0]))) {
  md += `## ${cat}\n\n`;
  md += `| Identifier | Real name | Line | Inheritance |\n`;
  md += `|---|---|---|---|\n`;
  for (const pkg of pkgs.sort()) {
    for (const reg of packages.get(pkg)) {
      const shortName = reg.realName.split(".").pop();
      const inherit = inheritance.find(i => i.child === reg.minified);
      const parentShort = inherit ? inherit.parent : "";
      md += `| \`${reg.minified || "—"}\` | ${shortName} | ${reg.line} | ${parentShort || ""} |\n`;
    }
  }
  md += `\n`;
}

// ── Output: Class boundaries (for chunking) ───────────────────────────
md += `## Class Boundaries (for chunking)\n\n`;
md += `Sorted by line number. Use these to split the bundle into feature modules.\n\n`;
md += `| Line | Class | Package | Category |\n`;
md += `|---|---|---|---|\n`;
for (const reg of classRegs) {
  const parts = reg.realName.split(".");
  const pkg = parts.length > 1 ? parts.slice(0, -1).join(".") : "(top-level)";
  const cat = classifyPackage(pkg);
  md += `| ${reg.line} | \`${reg.realName}\` | ${pkg} | ${cat} |\n`;
}

// ── Output: Inheritance tree ──────────────────────────────────────────
md += `\n## Inheritance Tree\n\n`;
const childToParent = new Map();
for (const i of inheritance) {
  childToParent.set(i.child, i.parent);
}
// Find root classes (no parent in our set)
const allChildren = new Set(inheritance.map(i => i.child));
const allParents = new Set(inheritance.map(i => i.parent));
const roots = [...allParents].filter(p => !allChildren.has(p));

function printTree(name, indent = 0) {
  const realName = nameMap.get(name) || name;
  const shortName = realName.split(".").pop();
  const line = classRegs.find(c => c.minified === name)?.line || "?";
  md += `${"  ".repeat(indent)}${shortName} (line ${line})\n`;
  const children = inheritance.filter(i => i.parent === name);
  for (const child of children) {
    printTree(child.child, indent + 1);
  }
}

for (const root of roots) {
  const realName = nameMap.get(root) || root;
  if (realName.startsWith("com.watabou.") || realName.startsWith("com.watabou.sevendrl")) {
    printTree(root);
  }
}

// ── Write outputs ─────────────────────────────────────────────────────
fs.writeFileSync(path.join(__dirname, "GLOSSARY.md"), md);

// JSON output for tooling
const jsonOut = {
  totalClasses: classRegs.length,
  classes: classRegs.map(r => ({
    realName: r.realName,
    minified: r.minified,
    line: r.line,
    kind: r.kind || "class",
    category: classifyPackage(r.realName.split(".").slice(0, -1).join(".")),
  })),
  inheritance: inheritance,
  nameMap: Object.fromEntries(nameMap),
};
fs.writeFileSync(path.join(__dirname, "identifier-glossary.json"), JSON.stringify(jsonOut, null, 2));

console.log(`Found ${classRegs.length} class/enum registrations`);
console.log(`Resolved ${nameMap.size} via __name__ assignments`);
console.log(`Found ${inheritance.length} inheritance relationships`);
console.log(`\nPackage categories:`);
for (const [cat, pkgs] of Object.entries(byClass).sort()) {
  const count = pkgs.reduce((sum, p) => sum + packages.get(p).length, 0);
  console.log(`  ${cat}: ${pkgs.length} packages, ${count} classes`);
}
console.log(`\nWrote GLOSSARY.md and identifier-glossary.json`);
